#!/usr/bin/env node
// patch-studio-c.cjs — Texte déplaçable (story) + muette par défaut (vidéo) +
// son off (story vidéo). Composants + affichage position légende.
const fs=require('fs'); const path=require('path'); const ROOT=process.cwd();
let ok=0,fail=0;
const good=m=>{console.log('  \u2705 '+m);ok++;};
const skip=m=>{console.log('  \u26a0\ufe0f  '+m);};
const err=m=>{console.log('  \u274c '+m);fail++;};
const read=r=>{const p=path.join(ROOT,r);return fs.existsSync(p)?fs.readFileSync(p,'utf8'):null;};
const write=(r,s)=>fs.writeFileSync(path.join(ROOT,r),s,'utf8');
function rep(r,from,to,l){const s=read(r);if(s==null){err('Introuvable: '+r);return;}if(s.includes(to)){good(l+' (déjà)');return;}if(!s.includes(from)){skip('Ancre manquante: '+l);return;}write(r,s.replace(from,to));good(l);}

console.log('\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');
console.log('  PATCH — Studio (texte déplaçable + muet)');
console.log('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n');

try { fs.writeFileSync(path.join(ROOT,'src/components/StoryStudio.jsx'), Buffer.from('','base64').toString('utf8'),'utf8'); good('StoryStudio.jsx mis à jour'); } catch(e){ err('StoryStudio: '+e.message); }
try { fs.writeFileSync(path.join(ROOT,'src/components/JejoStudio.jsx'), Buffer.from('','base64').toString('utf8'),'utf8'); good('JejoStudio.jsx mis à jour'); } catch(e){ err('JejoStudio: '+e.message); }

rep('src/pages/Home.jsx', `<div style={{ position:'absolute', left:24, right:24, bottom:24, textAlign:'center', color:'#fff', fontWeight:800, fontSize:22, textShadow:'0 2px 10px rgba(0,0,0,.7)', pointerEvents:'none', wordBreak:'break-word' }}>{cur.caption}</div>`, `<div style={ cur.captionPos ? { position:'absolute', left:(cur.captionPos.x*100)+'%', top:(cur.captionPos.y*100)+'%', transform:'translate(-50%,-50%)', maxWidth:'82%', textAlign:'center', color:'#fff', fontWeight:800, fontSize:22, textShadow:'0 2px 10px rgba(0,0,0,.7)', pointerEvents:'none', wordBreak:'break-word' } : { position:'absolute', left:24, right:24, bottom:24, textAlign:'center', color:'#fff', fontWeight:800, fontSize:22, textShadow:'0 2px 10px rgba(0,0,0,.7)', pointerEvents:'none', wordBreak:'break-word' }}>{cur.caption}</div>`, 'Affichage légende à la position (visionneuse)');

console.log('\n  Résultat: '+ok+' \u2705   '+fail+' \u274c');
if(fail===0) console.log('\n\ud83c\udf89 npx vite build\n'); else console.log('\n\u26a0\ufe0f envoie ce log.\n');
